# =============================================================================
# smart-scheduling-platform - setup.ps1
# Windows + Visual Studio 2022/2026
# Execute no PowerShell: cd C:\Git\smart-scheduling-platform ; .\setup.ps1
# =============================================================================

$ErrorActionPreference = "Stop"
$SOLUTION = "SmartScheduling"
$ROOT     = (Get-Location).Path
$SLN      = "$ROOT\$SOLUTION.sln"
$SRC      = "$ROOT\src"
$TESTS    = "$ROOT\tests"
$APP      = "$SRC\$SOLUTION.Application\$SOLUTION.Application.csproj"
$DOM      = "$SRC\$SOLUTION.Domain\$SOLUTION.Domain.csproj"
$INF      = "$SRC\$SOLUTION.Infrastructure\$SOLUTION.Infrastructure.csproj"
$API      = "$SRC\$SOLUTION.API\$SOLUTION.API.csproj"
$WRK      = "$SRC\$SOLUTION.Worker\$SOLUTION.Worker.csproj"
$DTST     = "$TESTS\$SOLUTION.Domain.Tests\$SOLUTION.Domain.Tests.csproj"
$ATST     = "$TESTS\$SOLUTION.API.Tests\$SOLUTION.API.Tests.csproj"

Write-Host ""
Write-Host "===============================================" -ForegroundColor Cyan
Write-Host "  smart-scheduling-platform setup" -ForegroundColor Cyan
Write-Host "  ROOT: $ROOT" -ForegroundColor Cyan
Write-Host "===============================================" -ForegroundColor Cyan
Write-Host ""

function Write-B64File([string]$RelPath, [string]$B64) {
    $full = "$ROOT\" + $RelPath.Replace('/', '\')
    $dir  = Split-Path $full -Parent
    if (!(Test-Path $dir)) { New-Item -ItemType Directory -Path $dir -Force | Out-Null }
    $bytes = [System.Convert]::FromBase64String($B64)
    [System.IO.File]::WriteAllBytes($full, $bytes)
}

Write-Host ">> Criando solution e projetos..." -ForegroundColor Yellow
dotnet new sln -n $SOLUTION -o $ROOT
dotnet new classlib -n "$SOLUTION.Domain"         -f net8.0 -o "$SRC\$SOLUTION.Domain"
dotnet new classlib -n "$SOLUTION.Application"    -f net8.0 -o "$SRC\$SOLUTION.Application"
dotnet new classlib -n "$SOLUTION.Infrastructure" -f net8.0 -o "$SRC\$SOLUTION.Infrastructure"
dotnet new webapi   -n "$SOLUTION.API"            -f net8.0 -o "$SRC\$SOLUTION.API"
dotnet new worker   -n "$SOLUTION.Worker"         -f net8.0 -o "$SRC\$SOLUTION.Worker"
dotnet new xunit    -n "$SOLUTION.Domain.Tests"   -f net8.0 -o "$TESTS\$SOLUTION.Domain.Tests"
dotnet new xunit    -n "$SOLUTION.API.Tests"      -f net8.0 -o "$TESTS\$SOLUTION.API.Tests"

Write-Host ">> Adicionando projetos a solution..." -ForegroundColor Yellow
dotnet sln $SLN add $DOM $APP $INF $API $WRK $DTST $ATST

Write-Host ">> Configurando referencias..." -ForegroundColor Yellow
